"use client";

import type { TimeRange } from "@workspace/ui/components/time-range-selector";
import type { ReactNode } from "react";
import { cn } from "@workspace/ui/lib/utils";
import {
  type LogsData,
  LogViewerProvider,
} from "./log-viewer.context";
import { LogViewerCountChart } from "./log-viewer.count-chart";
import {
  LogViewerListContent,
  LogViewerListHeader,
} from "./log-viewer.list";
import { LogViewerToolbar } from "./log-viewer.toolbar";

function LogViewerRoot({
  className,
  children,
}: {
  className?: string;
  children?: ReactNode;
}) {
  return (
    <div
      className={cn(
        "flex h-full min-h-0 flex-1 flex-col gap-2 overflow-hidden p-1",
        className
      )}
      data-slot="log-viewer"
    >
      {children}
    </div>
  );
}

function LogViewerList({
  className,
  children,
}: {
  className?: string;
  children?: ReactNode;
}) {
  return (
    <div
      className={cn(
        "flex min-h-0 flex-1 flex-col overflow-hidden rounded-md border",
        className
      )}
      data-slot="log-viewer-list"
    >
      {children}
    </div>
  );
}

function LogViewerVariant0({
  logs,
  className,
  onRefresh,
  timeRange,
  onTimeRangeChange,
  searchQuery,
  onSearchQueryChange,
}: {
  logs: LogsData;
  className?: string;
  onRefresh?: () => void;
  timeRange?: TimeRange;
  onTimeRangeChange?: (range: TimeRange) => void;
  searchQuery?: string;
  onSearchQueryChange?: (q: string) => void;
}) {
  return (
    <LogViewerProvider
      externalSearchQuery={searchQuery}
      externalTimeRange={timeRange}
      logs={logs}
      onRefresh={onRefresh}
      onSearchQueryChange={onSearchQueryChange}
      onTimeRangeChange={onTimeRangeChange}
    >
      <LogViewerRoot className={className}>
        <LogViewerToolbar />
        <LogViewerCountChart />
        <LogViewerList>
          <LogViewerListHeader />
          <LogViewerListContent />
        </LogViewerList>
      </LogViewerRoot>
    </LogViewerProvider>
  );
}

export const LogViewer = {
  Provider: LogViewerProvider,
  Root: LogViewerRoot,
  Toolbar: LogViewerToolbar,
  CountChart: LogViewerCountChart,
  List: LogViewerList,
  ListHeader: LogViewerListHeader,
  ListContent: LogViewerListContent,
  Variant0: LogViewerVariant0,
};

"use client";

import type { TimeRange } from "@workspace/ui/components/time-range-selector";
import {
  createContext,
  use,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";

export interface LogEntry {
  container: string;
  message: string;
  node: string;
  pod: string;
  stream: string;
  time: string;
}

export type LogsData = LogEntry[];

interface LogViewerContextValue {
  entries: LogEntry[];
  filteredEntries: LogEntry[];
  isLive: boolean;
  onRefresh?: () => void;
  searchQuery: string;
  selectedContainers: string[];
  selectedPods: string[];
  setIsLive: (v: boolean) => void;
  setSearchQuery: (q: string) => void;
  setSelectedContainers: (containers: string[]) => void;
  setSelectedPods: (pods: string[]) => void;
  setTimeRange: (range: TimeRange) => void;
  timeRange: TimeRange;
  uniqueContainers: string[];
  uniquePods: string[];
}

const LogViewerContext = createContext<LogViewerContextValue | null>(null);

export function useLogViewerContext() {
  const ctx = use(LogViewerContext);
  if (!ctx) {
    throw new Error(
      "LogViewer compound components must be used within LogViewer.Provider"
    );
  }
  return ctx;
}

export function LogViewerProvider({
  logs,
  children,
  onRefresh,
  externalTimeRange,
  onTimeRangeChange,
  externalSearchQuery,
  onSearchQueryChange,
}: {
  logs: LogsData;
  children: React.ReactNode;
  onRefresh?: () => void;
  externalTimeRange?: TimeRange;
  onTimeRangeChange?: (range: TimeRange) => void;
  externalSearchQuery?: string;
  onSearchQueryChange?: (q: string) => void;
}) {
  const [selectedPods, setSelectedPods] = useState<string[]>([]);
  const [selectedContainers, setSelectedContainers] = useState<string[]>([]);
  const [internalSearchQuery, setInternalSearchQuery] = useState("");
  const [internalTimeRange, setInternalTimeRange] = useState<TimeRange>({
    mode: "quick",
    ms: 5 * 60_000,
  });
  const [isLive, setIsLive] = useState(true);

  // Controlled-or-uncontrolled pattern
  const searchQuery =
    externalSearchQuery === undefined
      ? internalSearchQuery
      : externalSearchQuery;
  const setSearchQuery = onSearchQueryChange ?? setInternalSearchQuery;
  const timeRange = externalTimeRange ?? internalTimeRange;
  const setTimeRange = onTimeRangeChange ?? setInternalTimeRange;
  const onRefreshRef = useRef(onRefresh);
  onRefreshRef.current = onRefresh;

  useEffect(() => {
    if (!(isLive && onRefreshRef.current)) {
      return;
    }
    const id = setInterval(() => {
      onRefreshRef.current?.();
    }, 3000);
    return () => clearInterval(id);
  }, [isLive]);

  const uniquePods = useMemo(
    () => [...new Set(logs.map((e) => e.pod))].sort(),
    [logs]
  );

  const uniqueContainers = useMemo(
    () => [...new Set(logs.map((e) => e.container))].sort(),
    [logs]
  );

  const filteredEntries = useMemo(() => {
    let result = logs;
    // Time range filter
    if (timeRange.mode === "quick") {
      const cutoff = new Date(Date.now() - timeRange.ms).toISOString();
      result = result.filter((e) => e.time >= cutoff);
    } else {
      const start = timeRange.start.toISOString();
      const end = timeRange.end.toISOString();
      result = result.filter((e) => e.time >= start && e.time <= end);
    }
    if (selectedPods.length > 0) {
      result = result.filter((e) => selectedPods.includes(e.pod));
    }
    if (selectedContainers.length > 0) {
      result = result.filter((e) => selectedContainers.includes(e.container));
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter((e) => e.message.toLowerCase().includes(q));
    }
    return result;
  }, [logs, timeRange, selectedPods, selectedContainers, searchQuery]);

  const value: LogViewerContextValue = useMemo(
    () => ({
      entries: logs,
      filteredEntries,
      selectedPods,
      setSelectedPods,
      uniquePods,
      selectedContainers,
      setSelectedContainers,
      uniqueContainers,
      searchQuery,
      setSearchQuery,
      timeRange,
      setTimeRange,
      isLive,
      setIsLive,
      onRefresh,
    }),
    [
      logs,
      filteredEntries,
      selectedPods,
      uniquePods,
      selectedContainers,
      uniqueContainers,
      searchQuery,
      setSearchQuery,
      timeRange,
      setTimeRange,
      isLive,
      onRefresh,
    ]
  );

  return (
    <LogViewerContext.Provider value={value}>
      {children}
    </LogViewerContext.Provider>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import { useEffect, useState } from "react";
import {
  List,
  type RowComponentProps,
  useDynamicRowHeight,
} from "react-window";
import { type LogEntry, useLogViewerContext } from "./log-viewer.context";
import { highlightLogMessage } from "./log-viewer.highlight";
import { formatLogTime } from "./log-viewer.utils";

const LOG_GRID_TEMPLATE = "150px 1fr 80px 80px";

export function LogViewerListHeader() {
  return (
    <div
      className="flex flex-col border-b bg-muted-foreground/5"
      data-slot="log-viewer-header"
    >
      <div
        className="grid h-10 items-center gap-2 px-4 font-medium font-mono text-foreground text-xs"
        style={{ gridTemplateColumns: LOG_GRID_TEMPLATE }}
      >
        <span>Time</span>
        <span>Message</span>
        <span>Pod</span>
        <span>Container</span>
      </div>
    </div>
  );
}

function LogViewerRow({
  index,
  style,
  entries,
  searchQuery,
}: RowComponentProps<{ entries: LogEntry[]; searchQuery: string }>) {
  const entry = entries[index];
  if (!entry) {
    return null;
  }

  return (
    <div
      className={cn(
        "grid items-start gap-2 px-4 py-2 font-mono text-foreground text-xs",
        entry.stream === "stderr" && "border-theme-red/40 border-l-2"
      )}
      style={{ ...style, gridTemplateColumns: LOG_GRID_TEMPLATE }}
    >
      <span className="truncate text-muted-foreground">
        {formatLogTime(entry.time)}
      </span>
      <span className="line-clamp-3 whitespace-pre-wrap break-all">
        {highlightLogMessage(entry.message, searchQuery)}
      </span>
      <span className="truncate text-muted-foreground">{entry.pod}</span>
      <span className="truncate text-muted-foreground">{entry.container}</span>
    </div>
  );
}

/** `useDynamicRowHeight` uses ResizeObserver — only mount after hydration (SSR-safe). */
function VirtualizedListClient({
  entries,
  searchQuery,
}: {
  entries: LogEntry[];
  searchQuery: string;
}) {
  const rowHeight = useDynamicRowHeight({ defaultRowHeight: 28 });

  return (
    <List
      rowComponent={LogViewerRow}
      rowCount={entries.length}
      rowHeight={rowHeight}
      rowProps={{ entries, searchQuery }}
    />
  );
}

function VirtualizedList({
  entries,
  searchQuery,
}: {
  entries: LogEntry[];
  searchQuery: string;
}) {
  const [mounted, setMounted] = useState(false);
  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return <div aria-busy="true" className="h-full min-h-0 w-full" />;
  }

  return <VirtualizedListClient entries={entries} searchQuery={searchQuery} />;
}

export function LogViewerListContent() {
  const { entries, filteredEntries, searchQuery } = useLogViewerContext();

  if (entries.length === 0) {
    return (
      <div
        className="flex h-full min-h-0 flex-1 items-center justify-center bg-muted/50 p-6 text-muted-foreground"
        data-slot="log-viewer-empty"
      >
        No logs available.
      </div>
    );
  }

  if (filteredEntries.length === 0) {
    return (
      <div
        className="flex h-full min-h-0 flex-1 items-center justify-center bg-muted/50 p-6 text-muted-foreground"
        data-slot="log-viewer-empty"
      >
        No matching logs.
      </div>
    );
  }

  return (
    <div
      className="flex min-h-0 flex-1 overflow-hidden bg-muted/50 py-2"
      data-slot="log-viewer-content"
    >
      <VirtualizedList entries={filteredEntries} searchQuery={searchQuery} />
    </div>
  );
}

"use client";

import { Box, Download, Search, Server } from "lucide-react";
import { Button } from "@workspace/ui/components/button";
import { FacetedFilterAll } from "@workspace/ui/components/faceted";
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
} from "@workspace/ui/components/input-group";
import { LivePauseToggle } from "@workspace/ui/components/refresh-controls";
import { TimeRangeSelector } from "@workspace/ui/components/time-range-selector";
import {
  type LogEntry,
  useLogViewerContext,
} from "./log-viewer.context";

export function LogViewerToolbar() {
  const {
    searchQuery,
    setSearchQuery,
    isLive,
    setIsLive,
    filteredEntries,
    timeRange,
    setTimeRange,
    selectedPods,
    setSelectedPods,
    uniquePods,
    selectedContainers,
    setSelectedContainers,
    uniqueContainers,
  } = useLogViewerContext();

  return (
    <div className="flex items-center gap-2" data-slot="log-viewer-toolbar">
      {/* Filters */}
      <div className="flex items-center gap-1">
        <FacetedFilterAll
          className="w-28 border-0 shadow-none"
          emptyText="No pods found."
          icon={<Server />}
          label="Pod"
          onValueChange={setSelectedPods}
          options={uniquePods}
          searchPlaceholder="Search pods..."
          showLabel={false}
          value={selectedPods}
        />
        <FacetedFilterAll
          className="w-28 border-0 shadow-none"
          emptyText="No containers found."
          icon={<Box />}
          label="Container"
          onValueChange={setSelectedContainers}
          options={uniqueContainers}
          searchPlaceholder="Search containers..."
          showLabel={false}
          value={selectedContainers}
        />
        <TimeRangeSelector
          className="border-0 shadow-none"
          onChange={setTimeRange}
          value={timeRange}
        />
      </div>

      {/* Search + Actions */}
      <div className="flex flex-1 items-center gap-2">
        <InputGroup className="h-8 flex-1 dark:bg-muted/50">
          <InputGroupAddon>
            <Search className="size-4" />
          </InputGroupAddon>
          <InputGroupInput
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search logs..."
            value={searchQuery}
          />
        </InputGroup>
        <LivePauseToggle isLive={isLive} onToggle={() => setIsLive(!isLive)} />
        <Button
          onClick={() => downloadLogs(filteredEntries)}
          size="icon-sm"
          variant="outline"
        >
          <Download className="size-4" />
        </Button>
      </div>
    </div>
  );
}

function downloadLogs(entries: LogEntry[]) {
  const header = "time\tpod\tcontainer\tmessage";
  const lines = entries.map(
    (e) => `${e.time}\t${e.pod}\t${e.container}\t${e.message}`
  );
  const blob = new Blob([`${header}\n${lines.join("\n")}`], {
    type: "text/plain",
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `logs-${new Date().toISOString().slice(0, 19)}.txt`;
  a.click();
  URL.revokeObjectURL(url);
}

"use client";

import { useMemo } from "react";
import { Bar, BarChart, CartesianGrid, XAxis, YAxis } from "recharts";
import {
  type ChartConfig,
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
} from "@workspace/ui/components/chart";
import { useLogViewerContext } from "./log-viewer.context";
import { formatLogTime } from "./log-viewer.utils";

const chartConfig = {
  count: {
    label: "Count",
    color: "var(--chart-1)",
  },
} satisfies ChartConfig;

export function LogViewerCountChart() {
  const { filteredEntries, timeRange } = useLogViewerContext();

  const buckets = useMemo(() => {
    // Determine the full time range from the filter
    let rangeStart: number;
    let rangeEnd: number;
    if (timeRange.mode === "quick") {
      rangeEnd = Date.now();
      rangeStart = rangeEnd - timeRange.ms;
    } else {
      rangeStart = timeRange.start.getTime();
      rangeEnd = timeRange.end.getTime();
    }

    const span = rangeEnd - rangeStart;
    if (span <= 0) {
      return [
        { time: formatLogTime(new Date(rangeStart).toISOString()), count: 0 },
      ];
    }

    const bucketCount = 30;
    const interval = span / bucketCount;

    const counts = new Array<number>(bucketCount).fill(0);
    for (const e of filteredEntries) {
      const t = new Date(e.time).getTime();
      if (t < rangeStart || t > rangeEnd) {
        continue;
      }
      const idx = Math.min(
        Math.floor((t - rangeStart) / interval),
        bucketCount - 1
      );
      counts[idx] = (counts[idx] ?? 0) + 1;
    }

    return counts.map((count, i) => ({
      time: formatLogTime(new Date(rangeStart + i * interval).toISOString()),
      count,
    }));
  }, [filteredEntries, timeRange]);

  return (
    <ChartContainer
      className="aspect-auto h-[90px] w-full p-2"
      config={chartConfig}
      data-slot="log-viewer-count-chart"
    >
      <BarChart
        barCategoryGap="10%"
        data={buckets}
        margin={{ top: 4, right: 4, bottom: 0, left: 0 }}
      >
        <CartesianGrid strokeDasharray="3 3" vertical={false} />
        <XAxis
          axisLine={false}
          dataKey="time"
          fontSize={10}
          height={20}
          interval="preserveStartEnd"
          tickFormatter={(v: string) => {
            const parts = v.split(" ");
            return parts[1]?.slice(0, 5) ?? v;
          }}
          tickLine={false}
        />
        <YAxis
          allowDecimals={false}
          axisLine={false}
          fontSize={10}
          tickLine={false}
          width={24}
        />
        <ChartTooltip
          content={<ChartTooltipContent />}
          cursor={{ fill: "var(--color-count)", opacity: 0.1 }}
        />
        <Bar dataKey="count" fill="var(--color-count)" radius={[2, 2, 0, 0]} />
      </BarChart>
    </ChartContainer>
  );
}

import type { ReactNode } from "react";

const LOG_LEVEL_RE = /^(?:ERROR|WARN|INFO|DEBUG):?\s/;

const LEVEL_CLASS: Record<string, string> = {
  ERROR: "text-theme-red font-semibold",
  WARN: "text-theme-yellow font-semibold",
  INFO: "text-theme-blue font-semibold",
  DEBUG: "text-theme-gray",
};

function wrapSearch(text: string, q: string, key: string): ReactNode {
  const lower = text.toLowerCase();
  const idx = lower.indexOf(q);
  if (idx === -1) {
    return text;
  }

  const parts: ReactNode[] = [];
  let cursor = 0;
  let i = idx;
  let k = 0;
  while (i !== -1) {
    if (i > cursor) {
      parts.push(text.slice(cursor, i));
    }
    parts.push(
      <mark
        className="rounded-sm bg-theme-yellow/30 text-inherit"
        key={`${key}-${k++}`}
      >
        {text.slice(i, i + q.length)}
      </mark>
    );
    cursor = i + q.length;
    i = lower.indexOf(q, cursor);
  }
  if (cursor < text.length) {
    parts.push(text.slice(cursor));
  }
  return parts.length === 1 ? parts[0] : parts;
}

function renderPrefix(
  cls: string | undefined,
  prefix: string,
  q: string
): ReactNode {
  const content = q ? wrapSearch(prefix, q, "lv") : prefix;
  if (cls) {
    return <span className={cls}>{content}</span>;
  }
  return content;
}

export function highlightLogMessage(
  msg: string,
  searchQuery?: string
): ReactNode {
  if (!msg) {
    return msg;
  }

  const q =
    searchQuery && searchQuery.length >= 2 ? searchQuery.toLowerCase() : "";
  const levelMatch = msg.match(LOG_LEVEL_RE);

  if (!(levelMatch || q)) {
    return msg;
  }

  if (levelMatch) {
    const prefix = levelMatch[0];
    const lvl = prefix.replace(/[:\s]/g, "");
    const cls = LEVEL_CLASS[lvl];
    const rest = msg.slice(prefix.length);
    return (
      <>
        {renderPrefix(cls, prefix, q)}
        {q ? wrapSearch(rest, q, "r") : rest}
      </>
    );
  }

  return wrapSearch(msg, q, "s");
}

export function formatLogTime(iso: string): string {
  try {
    const d = new Date(iso);
    const y = d.getFullYear();
    const mo = String(d.getMonth() + 1).padStart(2, "0");
    const da = String(d.getDate()).padStart(2, "0");
    const h = String(d.getHours()).padStart(2, "0");
    const mi = String(d.getMinutes()).padStart(2, "0");
    const s = String(d.getSeconds()).padStart(2, "0");
    return `${y}/${mo}/${da} ${h}:${mi}:${s}`;
  } catch {
    return iso;
  }
}
